/* Aula 34 — modelJs: render com fragment + templates por função */

const listaEl = document.querySelector('#lista');

function createUserItem(u, selectedId) {
  const li = document.createElement('li');
  li.className = 'item';
  li.dataset.id = String(u.id);
  if (u.id === selectedId) li.classList.add('ativo');

  const box = document.createElement('div');
  box.className = 'stack';

  const strong = document.createElement('strong');
  strong.textContent = u.name;

  const email = document.createElement('span');
  email.className = 'muted';
  email.textContent = u.email;

  box.append(strong, email);
  li.appendChild(box);
  return li;
}

function renderLista(users, selectedId) {
  if (!listaEl) return;
  listaEl.innerHTML = '';

  const frag = document.createDocumentFragment();
  for (const u of users) {
    frag.appendChild(createUserItem(u, selectedId));
  }
  listaEl.appendChild(frag);
}
